const items = $input.all();
const nuevosItems = [];

for (const item of items) {
  // Creamos un nuevo objeto con todas las propiedades originales
  // y añadimos el campo 'text' con el valor de 'output'
  const nuevoItem = {
    json: {
      ...item.json,
      text: item.json.output,
      content: item.json.output
    }
  };
  nuevosItems.push(nuevoItem);
}

return nuevosItems;

const items = $input.all();
const nuevosItems = [];

// Función auxiliar para detectar si un texto pide una respuesta de sí o no
function detectarSiNo(texto) {
  if (!texto || typeof texto !== 'string') return false;
  const patrones = [
    /\b(sí|si)\s*\/\s*no\b/i,
    /\b(aceptas|confirmas|estás de acuerdo|quieres|deseas|te gustaría)\b.*\?/i,
    /^.*\?.*(sí|si).*(no).*$/i,
    /¿(deseas|quieres|te gustaría|estás seguro|aceptas)/i,
    /\b(yes|no)\b/i,
    /\b(responder (sí|si|no))\b/i
  ];
  return patrones.some(p => p.test(texto));
}

for (const item of items) {
  try {
    // El campo 'output' contiene un string JSON (puede venir escapado)
    let str = item.json.output;

    // Limpiar posibles escapes Unicode (ej: \u{1F6E0\uFE0F})
    str = str.replace(/\\u\{([^}]+)\}/g, (match, inner) => {
      const parts = inner.split(/\\u/);
      let result = '';
      for (let part of parts) {
        if (part === '') continue;
        result += String.fromCodePoint(parseInt(part, 16));
      }
      return result;
    });

    // Parsear el JSON principal (viene de la IA)
    const datosParseados = JSON.parse(str);

    // Verificar si el output contiene equipo_asignado: "Algo"
    if (datosParseados.output && typeof datosParseados.output === 'string') {
      const match = datosParseados.output.match(/^\s*equipo_asignado:\s*"([^"]*)"\s*$/);
      if (match) {
        datosParseados.equipo_asignado = match[1];
      }
    }

    // Combinar los campos originales (item.json) con los datos parseados
    const resultado = {
      ...item.json,           // conserva user_number, platform, conversation_id, etc.
      ...datosParseados,      // añade output, isMenu, session_id, etc.
      output: datosParseados.output  // asegurar que output sea el string correcto
    };

    // 🔥 Detección de isMenu (con respaldo por contenido si la IA falla)
    let isMenuValue = false;
    if (datosParseados.isMenu === true) {
      isMenuValue = true;
    } else if (datosParseados.output && typeof datosParseados.output === 'string') {
      const texto = datosParseados.output;
      if (texto.includes('¡Hola! 😊 Bienvenido/a') || 
          texto.includes('Para ayudarte mejor, por favor selecciona')) {
        isMenuValue = true;
      }
    }
    resultado.isMenu = isMenuValue;

    // 🔥 Detección de pregunta de sí/no (con prioridad al flag explícito)
    let esPreguntaSiNo = false;
    if (datosParseados.esPreguntaSiNo === true) {
      esPreguntaSiNo = true;
    } else if (datosParseados.output && typeof datosParseados.output === 'string') {
      esPreguntaSiNo = detectarSiNo(datosParseados.output);
    }
    resultado.esPreguntaSiNo = esPreguntaSiNo;

    nuevosItems.push({ json: resultado });

  } catch (e) {
    // En caso de error, conservar los datos originales
    nuevosItems.push({
      json: {
        error: e.message,
        original: item.json.output,
        ...item.json
      }
    });
  }
}

return nuevosItems;

