    item.json.phone_number_formatted = null;
    continue;
  }

  // Asegurar que sea string y tenga prefijo '+'
  phone = String(phone);
  if (!phone.startsWith('+')) {
    phone = '+' + phone;
  }
  item.json.phone_number_formatted = phone;
}
return items;

