const items = $input.all();
const nuevosItems = [];

// Función para escapar un texto para que sea válido dentro de un JSON
// (convierte saltos de línea a \n, comillas dobles a \", backslashes a \\, etc.)
function escaparParaWhatsApp(texto) {
  if (typeof texto !== 'string') return texto;
  // Usamos JSON.stringify para escapar completamente la cadena,
  // luego eliminamos las comillas dobles que añade al principio y al final.
  return JSON.stringify(texto).slice(1, -1);
}

for (const item of items) {
  // Copiar todo el objeto original
  const nuevoItem = { ...item.json };

  // Obtener el número de teléfono (igual que tu script)
  let phone = nuevoItem.user_number || nuevoItem.phone_number || nuevoItem.session_id;
  if (phone) {
    phone = String(phone);
    if (!phone.startsWith('+')) {
      phone = '+' + phone;
    }
    nuevoItem.phone_number_formatted = phone;
  } else {
    nuevoItem.phone_number_formatted = null;
  }

  // Escapar los campos que contienen texto para que WhatsApp los acepte
  if (nuevoItem.output) {
    nuevoItem.output = escaparParaWhatsApp(nuevoItem.output);
  }
  if (nuevoItem.text) {
    nuevoItem.text = escaparParaWhatsApp(nuevoItem.text);
  }
  if (nuevoItem.content) {
    nuevoItem.content = escaparParaWhatsApp(nuevoItem.content);
  }

  nuevosItems.push({ json: nuevoItem });
}

return nuevosItems;
